import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.专长","description":"","frontmatter":{},"headers":[],"relativePath":"8.粉红书/1.专长.md","filePath":"8.粉红书/1.专长.md"}'),b={name:"8.粉红书/1.专长.md"};function d(p,e,_,l,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"_1-专长",tabindex:"-1"},[s("1.专长 "),r("a",{class:"header-anchor",href:"#_1-专长","aria-label":'Permalink to "1.专长"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),o('<h1 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;写在前面&quot;">​</a></h1><p>丰乳肥臀——专长<br> 有些人在身体方面有着超乎常人的巨大变化，她们可能有着傲人的胸部或者丰硕的美臀，当然，这些巨大的变化，可不是仅仅只有视觉上的不同。这个能力分为两部分，可以交叉进行购买，也可以全部购买，购买时尊从专长购买方式，每一级的【丰乳】、【肥臀】的效果都需要单独支付进行购买。</p><p>一级<br> 丰乳：胸部更加丰满，意味着你在移动的时候可能需要更加坚固的胸衣来防止它们上下翻飞，也因此可能会造成你在移动上的不便，在计算体积时，额外增加1点，但是由胸部带来的体积变化，并不会带来来自移动速度的加成。<br> 肥臀：臀部肥美多汁，意味着你可能会产生更多的汗水，身体也会因此更加饱满，如果攻击的位置为腰部以下，你可以获得【防弹】效果。</p><p>二级：<br> 丰乳：更大，更大，更大，饱满多汁。饱满的胸部和发达的乳腺可以起到类似驼峰的储存效果，可以保证你在进行一次餐饮之后，在接下来的10+耐力天内不会饥饿和口渴，你也可以通过哺乳（不代表人物需要怀孕）的方式，满足队友1天的吃喝需求，每哺乳一名队友都会令你忍耐饥饿和口渴的天数降低1天。人物体积增加1，但是不会带来来自移动速度的加成。<br> 肥臀：鼓动，鼓动，鼓动，爽滑Q弹。丰腴的臀部和发达的肌肉可以带来更大的体积，人物体积增加2。如果攻击的位置为腰部以下，你可以获得1点偏斜防御。<br> 三级：<br> 丰乳：堆积如山的脂肪以及散发的浓重荷尔蒙气息。人物的体积再增加4点。胸部可以覆盖身体正面的大部分区域，这些区域在承受攻击时，视为拥有2点天生防御。<br> 肥臀：圆润的 外表以及内藏的强健筋肉。每个回合一次，获得一次额外移动的能力，可以最多移动15米。并且可以借助一些墙壁的凸起、绳索等进行短暂的空中飞行。<br> 固定型支撑<br> 500<br> 这是一个只有钢笔粗细的环形支撑，用法是由背后环绕至胸前，只能遮挡住敏感点，但是却可以保障胸部不会因为运动而四处摇摆，购买此物品后，专长中的体积增长会正常的带来移动上的加值。计算胸部带来的防御时，可以扩展到全身，并且增加1点护甲防御。</p><p>清爽型T字<br> 500<br> 具有汗液吸附能力的清爽T字裤裤，可以吸附由于剧烈运动带来的黏腻触感，在计算肥臀带来的偏斜防御时，增加2点。<br> 轮回者专长</p><p>丰乳肥臀（1）<br> 购买时价格等同D级技艺，且提供相同的属性。<br> 需要丰乳、肥臀其中一个购买至三级。<br> 挥洒的汗液，晃动的肢体，每一个都对男人充满了魅惑力。使用标准动作进行一次攻击，这次攻击可以不造成伤害，而是造成等额的魅惑点数，标准方式豁免，在使用该能力时，如果你购买了二级【丰乳】，则可以喷洒X汁，如果购买了二级【肥臀】，则可以挥洒汗液，并令目标进行豁免时降低2点。你的柰子和尻股会变为3L的天生武器，使用专业与攻击方式可以与ST进行商议。<br> 丰乳肥臀（2）<br> 购买时价格等同C级技艺，且提供相同的属性。<br> 男人不过是猎物罢了。使用标准动作进行一次攻击，目标需要已经带有魅惑点数或者在这次攻击中受到魅惑点数的影响，则这次攻击会变为【榨取】，方式由使用者决定，被攻击的目标会因为被榨取而陷入持续一个场景的力竭，标准方式豁免，这是一个C级创伤来源的效果。与一级的效果需要分别豁免。在此状态下，对【丰乳肥臀】造成的魅惑点数进行豁免时，豁免会再降低2点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const T=a(b,[["render",d]]);export{f as __pageData,T as default};
